// ─── Máquina de Estados del Flujo de Primera Cita ────────────────────────────

const BRIDGE_URL = 'http://host.docker.internal:3003';
const BRIDGE_KEY = 'cambia-esta-clave-secreta';
const CLINICA_URL = 'http://host.docker.internal:3000';
const N8N_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIwNTBmOGU2OC01M2VkLTRkYjktYWU3ZC01ZjY5NzJmMjE0N2EiLCJpc3MiOiJuOG4iLCJhdWQiOiJwdWJsaWMtYXBpIiwianRpIjoiYzE3YjViYzgtNzJjNC00ZjZlLTlkNjItMGZjMWI4Y2ExZDY5IiwiaWF0IjoxNzgwMDk0NjYzLCJleHAiOjE3ODI2MTkyMDB9.JWoNBV66ElxEalnyy063IgP-4US2aA_8-nv_PUzM89k';

const bridgeHeaders = { 'x-bridge-api-key': BRIDGE_KEY };
const clinicaHeaders = { 'x-n8n-api-key': N8N_KEY, 'Content-Type': 'application/json' };

// ─── Extraer datos del payload de forma flexible ───────────────────────────
const inputJson = $input.first().json;
// En n8n, el JSON recibido vía POST se guarda dentro de la propiedad .body
const body = inputJson.body || inputJson;

let desde = '';
let texto = '';

if (body.desde && body.texto) {
  // Formato simplificado y pre-procesado del Bridge MS
  desde = body.desde;
  texto = body.texto.trim();
} else {
  // Formato crudo de Whapi por si acaso
  const messages = body.messages || [];
  if (!messages.length) {
    return [{ json: { ignorar: true } }];
  }
  const msg = messages[0];
  const deMi = msg.from_me ?? msg.fromMe ?? false;
  if (deMi || msg.type !== 'text') {
    return [{ json: { ignorar: true } }];
  }
  desde = msg.chat_id || msg.chatId || msg.from || '';
  texto = (msg.text?.body || msg.body || '').trim();
}

const telefono = desde.replace('@s.whatsapp.net', '').replace('@c.us', '');

if (!texto || !telefono) {
  return [{ json: { ignorar: true } }];
}

// Comando global de reinicio
const textoLower = texto.toLowerCase();
if (['hola', 'inicio', 'nueva cita', 'cancelar', 'reiniciar', 'menu'].includes(textoLower)) {
  try {
    await $http.delete(`${BRIDGE_URL}/estado/${telefono}`, { headers: bridgeHeaders });
  } catch (e) {}
}

// ─── Obtener estado actual ─────────────────────────────────────────────────
let estadoActual = { estado: 'INICIO', datos: {} };
try {
  const resp = await $http.get(`${BRIDGE_URL}/estado/${telefono}`, { headers: bridgeHeaders });
  if (resp && resp.estado) estadoActual = resp;
} catch (e) {
  // 404 = sin conversación activa = INICIO
}

// Si se envió comando de reinicio, forzar INICIO
if (['hola', 'inicio', 'nueva cita', 'cancelar', 'reiniciar', 'menu'].includes(textoLower)) {
  estadoActual = { estado: 'INICIO', datos: {} };
}

const estado = estadoActual.estado || 'INICIO';
const datos = { ...(estadoActual.datos || {}) };

let respuesta = '';
let nuevoEstado = estado;
let nuevosDatos = { ...datos };
let emailDatos = null;
let limpiarEstado = false;

// ─── Máquina de estados ────────────────────────────────────────────────────
switch (estado) {
  case 'INICIO': {
    respuesta = `¡Bienvenido al *Centro de Rehabilitación y Fisioterapia*! 🏥\n\nPara agendar su primera cita, por favor envíeme su *nombre completo*.\n_(Ejemplo: Juan Pérez)_`;
    nuevoEstado = 'NOMBRE';
    break;
  }

  case 'NOMBRE': {
    const partes = texto.trim().split(/\s+/);
    nuevosDatos.nombre = partes[0];
    nuevosDatos.apellido = partes.slice(1).join(' ') || partes[0];
    respuesta = `Hola *${nuevosDatos.nombre}*! 👋\n\nAhora necesito su *número de Cédula de Identidad* (CI):`;
    nuevoEstado = 'CI';
    break;
  }

  case 'CI': {
    nuevosDatos.ci = texto.toUpperCase().replace(/[^A-Z0-9]/g, '');
    respuesta = `Perfecto. ¿Cuál es su *número de celular*?\n_(Puede ser diferente al de este WhatsApp)_`;
    nuevoEstado = 'TELEFONO';
    break;
  }

  case 'TELEFONO': {
    nuevosDatos.telefonoPaciente = texto.replace(/[^0-9+]/g, '');
    respuesta = `¿Cuál es su *correo electrónico*?\n_(Le enviaremos la confirmación de cita)_`;
    nuevoEstado = 'EMAIL';
    break;
  }

  case 'EMAIL': {
    nuevosDatos.email = texto.toLowerCase().trim();
    respuesta = `Por último, ¿cuál es el *motivo de su consulta*?\n_(Ej: Dolor lumbar, rehabilitación de rodilla, lesión deportiva)_`;
    nuevoEstado = 'MOTIVO';
    break;
  }

  case 'MOTIVO': {
    nuevosDatos.motivo = texto;

    // Registrar/recuperar paciente en Clínica
    let pacienteId = null;
    try {
      const pacResp = await $http.post(
        `${CLINICA_URL}/n8n/pacientes`,
        {
          headers: clinicaHeaders,
          body: {
            nombre: nuevosDatos.nombre,
            apellido: nuevosDatos.apellido,
            ci: nuevosDatos.ci,
            telefono: nuevosDatos.telefonoPaciente || telefono,
          },
        },
      );
      pacienteId = pacResp?.datos?.pacienteId;
    } catch (e) {
      respuesta = '⚠️ Hubo un error al registrar sus datos. Por favor escriba *Hola* para intentar nuevamente.';
      nuevoEstado = 'INICIO';
      limpiarEstado = true;
      break;
    }

    nuevosDatos.pacienteId = pacienteId;

    // Consultar disponibilidad del día siguiente (empleadoId=1 como fisioterapeuta por defecto)
    const manana = new Date();
    manana.setDate(manana.getDate() + 1);
    const fechaBusqueda = manana.toISOString().split('T')[0];
    nuevosDatos.fechaCita = fechaBusqueda;

    let bloques = [];
    try {
      const dispResp = await $http.get(
        `${CLINICA_URL}/n8n/disponibilidad?empleadoId=1&fecha=${fechaBusqueda}&duracion=60`,
        { headers: { 'x-n8n-api-key': N8N_KEY } },
      );
      bloques = dispResp?.datos?.bloques || [];
    } catch (e) {}

    if (bloques.length === 0) {
      respuesta = `Lo sentimos, no hay horarios disponibles para mañana *${fechaBusqueda}*.\n\nPor favor contáctenos directamente para encontrar una fecha disponible.\n📞 *Centro de Fisioterapia*`;
      nuevoEstado = 'INICIO';
      limpiarEstado = true;
    } else {
      const fmtHora = (iso) =>
        new Date(iso).toLocaleTimeString('es-BO', { hour: '2-digit', minute: '2-digit', hour12: true });
      const opciones = bloques
        .slice(0, 5)
        .map((b, i) => `  *${i + 1})* ${fmtHora(b.inicio)}`)
        .join('\n');
      nuevosDatos.bloques = bloques.slice(0, 5);
      respuesta = `✅ Sus datos fueron registrados exitosamente.\n\n📅 Horarios disponibles para *mañana ${fechaBusqueda}*:\n\n${opciones}\n\nResponda con el *número* de su preferencia:`;
      nuevoEstado = 'HORARIO';
    }
    break;
  }

  case 'HORARIO': {
    const opcion = parseInt(texto, 10);
    const bloques = datos.bloques || [];

    if (isNaN(opcion) || opcion < 1 || opcion > bloques.length) {
      respuesta = `Por favor responda con un número del *1* al *${bloques.length}* para confirmar su horario:`;
      nuevoEstado = 'HORARIO';
      break;
    }

    const bloqueElegido = bloques[opcion - 1];
    let citaId = null;

    // Agendar cita en Clínica
    try {
      const citaResp = await $http.post(
        `${CLINICA_URL}/n8n/citas`,
        {
          headers: clinicaHeaders,
          body: {
            pacienteId: datos.pacienteId,
            empleadoId: 1,
            fecha_hora: bloqueElegido.inicio,
            observaciones: datos.motivo
          }
        }
      );
      citaId = citaResp?.datos?.citaId;
    } catch (e) {
      respuesta = '⚠️ Error al agendar la cita. Por favor escriba *Hola* para intentar nuevamente.';
      nuevoEstado = 'INICIO';
      limpiarEstado = true;
      break;
    }

    // Confirmar cita
    if (citaId) {
      try {
        await $http.patch(
          `${CLINICA_URL}/n8n/citas/${citaId}/confirmar`,
          { headers: { 'x-n8n-api-key': N8N_KEY } }
        );
      } catch (e) {}
    }

    const fmtFecha = new Date(bloqueElegido.inicio).toLocaleDateString('es-BO', {
      weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
    });
    const fmtHora = new Date(bloqueElegido.inicio).toLocaleTimeString('es-BO', {
      hour: '2-digit', minute: '2-digit', hour12: true
    });

    respuesta = `🎉 *¡Cita Confirmada!*\n\n📅 *Fecha:* ${fmtFecha}\n🕐 *Hora:* ${fmtHora}\n🏥 *Lugar:* Centro de Rehabilitación y Fisioterapia\n\n_Se envió un email de confirmación a ${datos.email || 'su correo'}._\n\nEsperamos verle pronto. Recuerde llegar 10 minutos antes. ✨`;

    if (datos.email) {
      emailDatos = {
        para: datos.email,
        asunto: 'Confirmación de Cita — Centro de Fisioterapia',
        nombre: `${datos.nombre || ''} ${datos.apellido || ''}`.trim(),
        fechaHora: `${fmtFecha} a las ${fmtHora}`,
        motivo: datos.motivo || 'No especificado'
      };
    }

    nuevoEstado = 'COMPLETADO';
    limpiarEstado = true;
    break;
  }

  default: {
    respuesta = 'Escriba *Hola* para agendar una nueva cita. 😊';
    nuevoEstado = 'INICIO';
    limpiarEstado = true;
    break;
  }
}

// ─── Actualizar o limpiar estado ───────────────────────────────────────────
if (limpiarEstado) {
  try {
    await $http.delete(`${BRIDGE_URL}/estado/${telefono}`, { headers: bridgeHeaders });
  } catch (e) {}
} else {
  try {
    await $http.put(
      `${BRIDGE_URL}/estado/${telefono}`,
      {
        headers: { ...bridgeHeaders, 'Content-Type': 'application/json' },
        body: { estado: nuevoEstado, datos: nuevosDatos }
      }
    );
  } catch (e) {}
}

return [{
  json: {
    waDestino: desde,
    waMensaje: respuesta,
    emailDatos,
    ignorar: !respuesta
  }
}];
